{"procName":"dbo.stockbalances_issuedstock_returnsupplier","body":"CREATE PROCEDURE [dbo].[StockBalances_IssuedStock_ReturnSupplier]
(
	@SourceType nvarchar(50),
	@lenhcapphat nvarchar(50),
	@phieuxuat nvarchar(50),
	@makho nvarchar(50),
	@mact nvarchar(100),
	@soluong decimal(18, 5),
	@ghichu nvarchar(max),
	@nguoitao nvarchar(50),
	@id_pyc_chitiet uniqueidentifier, -- liên kết bảng tr_phieuyeucau_chitiet
	@id_chitiet_dathang int, -- liênn kết với bảng tr_dondathang_chitiet
	@id_chitiet_lcp int, -- liên kế bảng tr_lenhcapphat
	@id_chitiet_phieunhap int, -- liên kết bảng tr_ctphieunhap
	@BatchNo nvarchar(50)
)
AS
BEGIN

	DECLARE @UnitPrice DECIMAL(18, 5);

	DECLARE @TransactionDate DATETIME = GETDATE();
	DECLARE @SourceId int;

	-- ĐIỀU CHỈNH LẠI MÃ KHO THEO MÃ CHI TIẾT (1 MÃ CHỈ NẰM Ở 1 KHO)
	DECLARE @makho_dieuchinh nvarchar(50);
	SET @makho_dieuchinh = dbo.ufn_GetWHSMaterial(@mact);

	SELECT TOP 1 @UnitPrice = UnitPrice FROM StockTransaction 
	WHERE WarehouseCode = @makho_dieuchinh AND MaterialCode = @mact AND BatchNo = @BatchNo
		AND SourceType = 'IN'
	ORDER BY TransactionDate ASC

	-- GHI CHI TIẾT PHIẾU XUẤT
	INSERT INTO tr_ctphieuxuat 
	(
		lenhcapphat, phieuxuat, makho, mact, soluong, ghichu, ngaytao, nguoitao,
		id_pyc_chitiet, id_chitiet_dathang, id_chitiet_lcp, id_chitiet_phieunhap, BatchNo
	)
	VALUES (
		@lenhcapphat, @phieuxuat, @makho, @mact, @soluong, @ghichu, @TransactionDate, @nguoitao,
		@id_pyc_chitiet, @id_chitiet_dathang, @id_chitiet_lcp, @id_chitiet_phieunhap, @BatchNo
	)
	SET @SourceId = SCOPE_IDENTITY();

	-- ghi giao dịch xuất kho
	INSERT INTO StockTransaction
	(
		TransactionDate, SourceType, SourceId, WarehouseCode, MaterialCode,
		BatchNo, Quantity, UnitPrice, SupplierCode, CreatedBy, Note
	)
	VALUES (
		@TransactionDate, @SourceType, @SourceId, @makho_dieuchinh, @mact,
		@BatchNo, -@soluong, @UnitPrice, null, @nguoitao, @ghichu
	)

	-- cập nhật tồn kho
	UPDATE StockBalances
	SET Quantity = Quantity - @soluong
	WHERE WarehouseCode = @makho_dieuchinh AND MaterialCode = @mact AND BatchNo = @BatchNo

	IF @id_chitiet_dathang IS NOT NULL
	BEGIN
		-- XUẤT KHO TRẢ NHÀ CUNG CẤP
		UPDATE tr_dondathang_chitiet
		SET sl_danhan = sl_danhan - @soluong,
			sl_conlai = sl_conlai + @soluong
		WHERE id = @id_chitiet_dathang
	END

END
